{"command": "cd /testbed && python << 'EOF'
with open('django/db/backends/ddl_references.py', 'r') as f:
    content = f.read()

# Fix 1: Columns.__str__ - add space before non-empty suffix
old1 = '''    def __str__(self):
        def col_str(column, idx):
            try:
                return self.quote_name(column) + self.col_suffixes[idx]
            except IndexError:
                return self.quote_name(column)

        return ', '.join(col_str(column, idx) for idx, column in enumerate(self.columns))'''

new1 = '''    def __str__(self):
        def col_str(column, idx):
            try:
                col = self.quote_name(column)
                if self.col_suffixes[idx]:
                    col = '{} {}'.format(col, self.col_suffixes[idx])
                return col
            except IndexError:
                return self.quote_name(column)

        return ', '.join(col_str(column, idx) for idx, column in enumerate(self.columns))'''

content = content.replace(old1, new1)

# Fix 2: IndexColumns.__str__ - only add suffix with space when non-empty
old2 = '''    def __str__(self):
        def col_str(column, idx):
            # Index.__init__() guarantees that self.opclasses is the same
            # length as self.columns.
            col = '{} {}'.format(self.quote_name(column), self.opclasses[idx])
            try:
                col = '{} {}'.format(col, self.col_suffixes[idx])
            except IndexError:
                pass
            return col

        return ', '.join(col_str(column, idx) for idx, column in enumerate(self.columns))'''

new2 = '''    def __str__(self):
        def col_str(column, idx):
            # Index.__init__() guarantees that self.opclasses is the same
            # length as self.columns.
            col = '{} {}'.format(self.quote_name(column), self.opclasses[idx])
            try:
                if self.col_suffixes[idx]:
                    col = '{} {}'.format(col, self.col_suffixes[idx])
            except IndexError:
                pass
            return col

        return ', '.join(col_str(column, idx) for idx, column in enumerate(self.columns))'''

content = content.replace(old2, new2)

with open('django/db/backends/ddl_references.py', 'w') as f:
    f.write(content)

print('Done')
EOF
"}

